  # This solves the chicken-and-egg problem: ___batch2 needs .tmp/batch-exits/
  # Note: init is also a batch combinator, so it needs this structure to exist
  # Extract permissions from VPN_SWITCH_INIT_DIR_CONFIG
  local tmp_mode=$(echo "$VPN_SWITCH_INIT_DIR_CONFIG" | grep '^\.tmp:' | cut -d: -f2)
  local batch_exits_mode=$(echo "$VPN_SWITCH_INIT_DIR_CONFIG" | grep '^\.tmp/batch-exits:' | cut -d: -f2)

  # Create base directory if needed
  if [ ! -d "$basedir" ]; then
    $MODIFY_DIR_CREATE "$basedir"
    $MODIFY_FILE_PERMS 0700 "$basedir"
  fi

  # Create .tmp if needed (operational directory - may have content)
  if [ ! -d "$basedir/.tmp" ]; then
