    $MODIFY_FILE_PERMS "$tmp_mode" "$basedir/.tmp"
  fi

  # Create .tmp/batch-exits if needed (operational directory - may have content)
  if [ ! -d "$basedir/.tmp/batch-exits" ]; then
    $MODIFY_DIR_CREATE "$basedir/.tmp/batch-exits"
    $MODIFY_FILE_PERMS "$batch_exits_mode" "$basedir/.tmp/batch-exits"
