  # Command 1: init with minimal environment overrides
  # Use simple interpreters for bootstrap (sh instead of complex pipelines)
  # VPN_SWITCH_CONTEXT_BOOTSTRAPPED=1 tells the script to use CACHE_ENV_ARGS
  echo "VPN_SWITCH_BASE=\"$basedir\" VPN_SWITCH_CONTEXT_BOOTSTRAPPED=1 VPN_SWITCH_CACHE_ENV_ARGS=\"PATH=/bin:/usr/bin:/usr/local/bin VPN_SWITCH_BATCH_KEEP_GOING=0 VPN_SWITCH_TERMINAL_INTERPRETER=/bin/sh VPN_SWITCH_COMBINATOR_INTERPRETER=/bin/sh VPN_SWITCH_BATCH_COMBINATOR_INTERPRETER=/bin/sh VPN_SWITCH_INTERPRETER_lift1=cat\" \"\$VPN_SWITCH_CONTEXT_SCRIPT\" init $profile"

