  echo "VPN_SWITCH_BASE=\"$basedir\" VPN_SWITCH_CONTEXT_BOOTSTRAPPED=1 PATH=/bin:/usr/bin:/usr/local/bin VPN_SWITCH_TERMINAL_INTERPRETER=/bin/sh VPN_SWITCH_COMBINATOR_INTERPRETER=/bin/sh VPN_SWITCH_BATCH_COMBINATOR_INTERPRETER=/bin/sh \"\$VPN_SWITCH_CONTEXT_SCRIPT\" version sync"

  # Command 3: success log
  # Need same environment variables for log command
  echo "VPN_SWITCH_BASE=\"$basedir\" VPN_SWITCH_CONTEXT_BOOTSTRAPPED=1 VPN_SWITCH_CACHE_ENV_ARGS=\"PATH=/bin:/usr/bin:/usr/local/bin VPN_SWITCH_TERMINAL_INTERPRETER=/bin/sh\" \"\$VPN_SWITCH_CONTEXT_SCRIPT\" log 'Bootstrap complete: $basedir ($profile)'"
}

#@help _lift1
# @internal phase-lifting helper (plain shell -> terminal function)
#@end
_lift1() {
  local phase_name="$1"

  if [ -z "$phase_name" ]; then
    display error "lift requires phase name argument"
    display plain "Usage: cat input.sh | vpn-switch lift <phase>"
    return 1
  fi

  # Read input from stdin, skip shebang if present
  local input_content=$(cat)
  local commands=$(echo "$input_content" | tail -n +2)

  # If input didn't have shebang, use all content
  if ! echo "$input_content" | head -1 | grep -q '^#!/'; then
    commands="$input_content"
  fi

  # Escape runtime variables so they survive heredoc expansion
  # Variables like $?, $@, $*, $1, $2, etc. need to be escaped
  local escaped=$(echo "$commands" | sed 's/\$?/\\$?/g; s/\$@/\\$@/g; s/\$\*/\\$*/g; s/\$\([0-9]\)/\\$\1/g')

  # Output lifted template to stdout
  cat <<LIFT_OUTER
#!/bin/sh
# Auto-generated phase template (lifted from simple format)

# Unpack context variables (for generation-time expansion)
eval "\$VPN_SWITCH_CONTEXT_CONNECT"

case "\$1" in
    verify)
        cat <<'EOF'
# Verify function for $phase_name phase
verify_${phase_name}() {
    local step="\$1"
    local exit_code="\$2"

    case "\$step" in
        prepare)
            if [ "\$exit_code" -ne 0 ]; then
                echo "# ERROR: $phase_name prepare failed" >&2
                exit 1
            fi
            echo "# ✓ $phase_name prerequisites met" >&2
            ;;
        execute)
            if [ "\$exit_code" -ne 0 ]; then
                echo "# ERROR: $phase_name configuration failed" >&2
                exit 1
            fi
            echo "# ✓ $phase_name configured successfully" >&2
            ;;
    esac
}
EOF
        ;;

    prepare)
        cat <<'EOF'
echo "# ==> Phase: $phase_name (prepare)" >&2
verify_${phase_name} prepare 0
EOF
        ;;

    execute)
        cat <<EOF
echo "# ==> Phase: $phase_name (execute)" >&2

$escaped
verify_${phase_name} execute \\\$?
EOF
        ;;

    inspect)
        cat <<EOF
echo "### $phase_name Phase"
echo "Context: interface=\$interface"
EOF
        ;;

    *)
        echo "# Usage: \\\$0 {verify|prepare|execute|inspect}" >&2
        exit 1
        ;;
esac
LIFT_OUTER
}

#@help _database_init0
# @internal database-structure init chain step
#@end
_database_init0() {
  local base="$VPN_SWITCH_BASE"

  echo "# Initialize VPN switch database: $base"
  echo "PATH=/bin:/usr/bin:/usr/local/bin"

  # Generation time: iterate config, check state, emit concrete commands
  echo "$VPN_SWITCH_INIT_DIR_CONFIG" | while IFS=: read -r dir mode exec_flag content_policy; do
    [ -z "$dir" ] && continue
    local full_path="$base/$dir"

    if [ -e "$full_path" ]; then
      # Directory exists - validate at generation time

      # 1. Must be a directory
      if [ ! -d "$full_path" ]; then
        echo "echo '# Error: Path exists but is not a directory: $dir' >&2"
        echo "echo '# Please remove the file and run init again.' >&2"
        echo "exit 1"
        continue
      fi

      # 2. Check content policy
      case "$content_policy" in
        operational)
          # Allow existing content
          ;;
        exclusive|*)
          # Must be empty for security
          if [ -n "$(ls -A "$full_path" 2>/dev/null)" ]; then
            echo "echo '# Error: Directory $dir exists but is not empty' >&2"
            echo "echo '# Exclusive hierarchy required for security.' >&2"
            echo "exit 1"
            continue
          fi
          ;;
      esac

      # 3. Check permissions (warn only)
      local actual_mode=$($CMD_STAT_PERMS "$full_path" 2>/dev/null)
      local normalized_expected=$(echo "$mode" | sed 's/^0*//')
      local normalized_actual=$(echo "$actual_mode" | sed 's/^0*//')
      if [ "$normalized_actual" != "$normalized_expected" ]; then
        echo "echo '# Warning: Directory $dir has mode $actual_mode, expected $mode' >&2"
      fi

      # 4. Exec flag check
      if [ "$exec_flag" = "exec" ]; then
        local test_script="$full_path/.init_exec_test_$$"
        echo "#!/bin/sh" > "$test_script"
        echo "exit 0" >> "$test_script"
        $MODIFY_FILE_PERMS 0700 "$test_script"
        if ! "$test_script" 2>/dev/null; then
          $MODIFY_FILE_REMOVE "$test_script"
          echo "echo '# Error: Directory $dir requires exec mount but is mounted noexec' >&2"
          echo "exit 1"
          continue
        fi
        $MODIFY_FILE_REMOVE "$test_script"
      fi

      echo "echo '# Validated: $dir' >&2"
    else
      # Directory doesn't exist - emit create commands
      echo "$MODIFY_DIR_CREATE '$full_path'"
      echo "$MODIFY_FILE_PERMS $mode '$full_path'"
      echo "echo '# Created: $dir (mode $mode)' >&2"
    fi
  done

  # Protocol extension links
  echo "cd '$base' || exit 1"
  [ -L "$base/conf" ] || echo "$MODIFY_LINK_FORCE wireguard conf"
  [ -L "$base/ovpn" ] || echo "$MODIFY_LINK_FORCE openvpn ovpn"
  echo "echo '# Database ready: $base' >&2"
}

#@help _environment_init1
# @internal environment-defaults init helper (copy profile to .env/default)
#@end
_environment_init1() {
  local profile="${1:-minimal}"
  local base="$VPN_SWITCH_BASE"
  local cache_file="$base/.env/local/VPN_SWITCH_CACHE_ENV_ARGS"
  local profile_upper
  profile_upper=$(echo "$profile" | tr '[:lower:]' '[:upper:]')
  local profile_var="VPN_SWITCH_PROFILE_${profile_upper}"
  local profile_file="$VPN_SWITCH_TEMPLATE_DIR/environment/$profile_var"

  # Validation at generation time
  if [ ! -f "$profile_file" ]; then
    echo "echo '# Error: Unknown profile: $profile' >&2"
    echo "echo '# Looking for: $profile_file' >&2"
    echo "exit 1"
    return 1
  fi

  if [ ! -d "$VPN_SWITCH_TEMPLATE_DIR/environment" ]; then
    echo "echo '# Error: Template directory not found' >&2"
    echo "exit 1"
    return 1
  fi

  echo "# Install environment templates for profile: $profile"

  # Generation time: iterate templates, emit concrete commands
  local var_list
  var_list=$(head -1 "$profile_file")
  for varname in $var_list; do
    local template="$VPN_SWITCH_TEMPLATE_DIR/environment/$varname"
    if [ -f "$template" ]; then
      echo "$MODIFY_FILE_COPY_FORCE '$template' '$base/.env/default/$varname'"
      echo "$MODIFY_FILE_PERMS 0600 '$base/.env/default/$varname'"
    else
      echo "echo '# Warning: Template not found: $varname' >&2"
    fi
  done

  # Profile marker
  echo "$MODIFY_FILE_COPY_FORCE '$profile_file' '$base/.env/default/$profile_var'"
  echo "$MODIFY_FILE_PERMS 0600 '$base/.env/default/$profile_var'"

  # Invalidate cache if exists
  if [ -f "$cache_file" ]; then
    echo "$MODIFY_FILE_REMOVE '$cache_file'"
    echo "echo '# Cache invalidated' >&2"
  fi

  echo "echo '# Installed $profile profile' >&2"
}

