#@help _environment_cache1
# @internal arity-1 sibling of 'environment cache' (on|off|status)
#@end
_environment_cache1() {
  local cmd="$1"
  local cache_file="$VPN_SWITCH_BASE/.env/local/VPN_SWITCH_CACHE_ENV_ARGS"

  case "$cmd" in
    on)
      # Generation time: write cache directly (ESSENCE).
      # Force a fresh disk scan: build_env_args_full short-circuits on an
      # in-memory VPN_SWITCH_CACHE_ENV_ARGS (inherited via env -), so without
      # unsetting it here a rebuild would just rewrite the stale value it is
      # meant to replace. Unset in a subshell so the scan reads .env/ afresh.
      ( unset VPN_SWITCH_CACHE_ENV_ARGS; build_env_args_full ) > "$cache_file"
      $MODIFY_FILE_PERMS 0600 "$cache_file"
      local var_count
      var_count=$(wc -w < "$cache_file" | tr -d ' ')

      echo "echo '# Environment cache ENABLED' >&2"
      echo "echo '# Cached $var_count variables' >&2"
      ;;

    off)
      # Generation time: check and act
      if [ -f "$cache_file" ]; then
        echo "$MODIFY_FILE_REMOVE '$cache_file'"
        echo "echo '# Environment cache DISABLED' >&2"
      else
        echo "echo '# Environment cache already disabled' >&2"
      fi
      ;;

    status|"")
      # Generation time: examine and report
      if [ -f "$cache_file" ]; then
        local var_count
        var_count=$(wc -w < "$cache_file" | tr -d ' ')
        echo "echo '# Environment cache: ENABLED ($var_count vars)' >&2"
      else
        echo "echo '# Environment cache: DISABLED' >&2"
      fi
      ;;

    *)
      echo "echo '# Error: Unknown cache command: $cmd' >&2"
      echo "exit 1"
      ;;
  esac
}

#@help _lift3
# @internal phase-lifting helper (3-arg form)
#@end
_lift3() {
  local phase_name="$1"
  local input_file="$2"
  local output_file="$3"

  # Security: Require absolute paths to prevent writing outside database
  case "$output_file" in
    /*)
      # Absolute path - OK
      ;;
    *)
      generate_error "lift requires absolute output path" "Got relative path: $output_file"
      return 0
      ;;
  esac

  case "$input_file" in
    /*)
      # Absolute path - OK
      ;;
    *)
      generate_error "lift requires absolute input path" "Got relative path: $input_file"
      return 0
      ;;
  esac

  local output_dir=$(dirname "$output_file")

  # Generation time: create directory and write file
  $MODIFY_DIR_CREATE "$output_dir"
  lift_phase_simple "$input_file" "$phase_name" "$output_file"
  $MODIFY_FILE_PERMS +x "$output_file"

  # Output: status message for execution time
  echo "echo '# ✓ Lifted: $phase_name' >&2"
}

#@help __phases_lift1
# @internal phase-lifting chain step
#@end
__phases_lift1() {
  local phase_backend="$1"

  if [ -z "$phase_backend" ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" error 'phases lift requires phase:backend argument'"
    return 0
  fi

  # Split phase:backend
  local phase_name=$(echo "$phase_backend" | cut -d: -f1)
  local backend_name=$(echo "$phase_backend" | cut -d: -f2)

  if [ -z "$phase_name" ] || [ -z "$backend_name" ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" error 'Invalid format: $phase_backend - expected phase:backend'"
    return 0
  fi

  # Resolve profile name from template/phase/default symlink
  local profile_name="base"
  if [ -L "$VPN_SWITCH_TEMPLATE_DIR/phase/default" ]; then
    profile_name=$(basename "$(readlink "$VPN_SWITCH_TEMPLATE_DIR/phase/default")")
  fi

  local input_file="$VPN_SWITCH_TEMPLATE_DIR/phase/$profile_name/$phase_name/${backend_name}.sh"
  local output_file="$VPN_SWITCH_BASE/.include/phase/$profile_name/$phase_name/${backend_name}.sh"

  # Validation at generation time
  if [ ! -f "$input_file" ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" error 'Backend template not found: $input_file'"
    return 0
  fi

  # Delegate to lift terminal function
  echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" lift '$phase_name' '$input_file' '$output_file'"
}

