  echo "VPN_SWITCH_CACHE_ENV_ARGS=\"VPN_SWITCH_COMBINATOR_INTERPRETER=sh VPN_SWITCH_TERMINAL_INTERPRETER=sh VPN_SWITCH_BATCH_COMBINATOR_INTERPRETER='while IFS= read -r line; do echo \\\"\\\$line\\\" | \\\$VPN_SWITCH_COMBINATOR_INTERPRETER; done'\" \"\$VPN_SWITCH_CONTEXT_SCRIPT\" init minimal"
